    def fourSumCount(self, A, B, C, D):
        """
        :type A: List[int]
        :type B: List[int]
        :type C: List[int]
        :type D: List[int]
        :rtype: int
        """
        counter = {}
        result = 0
        for a in A:
            for b in B:
                s = a + b
                if s in counter:
                    counter[s] += 1
                else:
                    counter[s] = 1
        for c in C:
            for d in D:
                s = -1 * (c + d)
                if s in counter:
                    result += counter[s]
        return result

