    parentName: "pre"
  }, {}), "import heapq
class Solution(object):
    def getSkyline(self, buildings):
        """
        :type buildings: List[List[int]]
        :rtype: List[List[int]]
        """
        if not buildings or not buildings[0]:
            return []
        # 构建列表
        coors = []
        for b in buildings:
            coors.append((b[0], -b[2]))
            coors.append((b[1], b[2]))
        # 列表排序
        coors.sort(key=lambda x: (x[0], x[1]))
        # 开始遍历
        data = []
        res = []
        pre, cur = 0, 0
        heapq.heappush(data, 0)
        for c in coors:
            # 【1】本该是将负值变为正值进堆，但heapq是小根堆，所以这里是将正值变为负值进堆，这样堆的最小值取负之后就是实际的最大值
            if c[1] < 0:
                heapq.heappush(data, c[1])  
            else:
                data.remove(-c[1]) # 【2】
                heapq.heapify(data)
            cur = -1 * data[0]
            if cur != pre:
                res.append([c[0], cur])
