class Solution(object):
    def getSkyline(self, buildings):
        # 把左边界和右边界的横轴坐标保留下来
        x = [i[0] for i in buildings] + [i[1] for i in buildings]
        # 排序
        x.sort()
        index = 0
        heap = []
        res = [[0, 0]]
        # 从小到大的顺序循环边界的值
        for i in x:

            # 先来判断这个点是不是左边界，如果是左边界，则把对应的建筑加入堆中。

            #  index表示的是建筑的编号，找到建筑左边界等于i的建筑放到大根堆
            # （这里看似是while，但其实每个建筑只被处理了一次，因为x是按照从小到大排的，buildings也是按照左边界从小到大排的，所以没有问题～
            while index < len(buildings) and buildings[index][0] == i:
                # 大根堆存放的是（高，右边界）
                heapq.heappush(heap, (-buildings[index][2], buildings[index][1]))
                # 建筑编号加1
                index += 1

            # 大根堆的堆顶元素即建筑的最高值
            # 来判断下这栋建筑的右边界，如果右边界小于等于i，即该建筑已经遍历完了，不需要了，则从堆中移出，依次类推
            while heap and heap[0][1] <= i:
                heapq.heappop(heap)
            # 如果堆里仍然有值，把堆顶的元素的高取出来就是当前点的最高
            h = -heap[0][0] if heap else 0
            # 和结果中的高进行对比，如果不相同，说明不在一条直线上，把该值添加到res中
            if h != res[-1][1]:
                res.append([i, h])

